__d(function(g,r,i,a,m,e,d){"use strict";Object.defineProperty(e,'__esModule',{value:!0}),Object.defineProperty(e,"GLOSSARY",{enumerable:!0,get:function(){return n}}),e.getGlossaryEntry=function(l){return n[l]||null};const n={arketip:{term:'Arketip',short:'T\xfcm insanl\u0131\u011f\u0131n payla\u015ft\u0131\u011f\u0131 evrensel i\xe7 desen.',long:"Arketip, Jung'un kuram\u0131nda, kolektif bilin\xe7d\u0131\u015f\u0131nda yatan ve t\xfcm k\xfclt\xfcrlerde tekrar tekrar ortaya \xe7\u0131kan evrensel i\xe7 desenlere verilen add\u0131r. Persona, G\xf6lge, Anima, Animus, Self, Kahraman, Trickster, Bilge Ya\u015fl\u0131 gibi fig\xfcrler birer arketiptir.\n\nArketipler tek ba\u015f\u0131na \"iyi\" ya da \"k\xf6t\xfc\" de\u011fildir; her birinin ayd\u0131nl\u0131k ve g\xf6lge y\xfcz\xfc vard\u0131r. Onlar\u0131 tan\u0131mak, i\xe7sel yap\u0131n\u0131 anlaman\u0131n ve b\xfct\xfcnle\u015fmenin yoludur."},mit:{term:'Mit',short:'Bir k\xfclt\xfcr\xfcn bilin\xe7alt\u0131n\u0131 ta\u015f\u0131yan derin hikaye.',long:"Mit, tarihsel olarak do\u011fru olmasa da psikolojik olarak \xe7ok derin bir ger\xe7e\u011fi ta\u015f\u0131yan anlat\u0131d\u0131r. Prometheus'un ate\u015fi, \u0130nanna'n\u0131n yer alt\u0131na ini\u015fi, Orpheus ve Eurydike \u2014 hepsi insan ruhunun temel meselelerini sembolik dilde anlat\u0131r.\n\nJung der ki mitler, bir halk\u0131n r\xfcyalar\u0131d\u0131r. Bireyin r\xfcyalar\u0131 nas\u0131l bilin\xe7alt\u0131n\u0131 ta\u015f\u0131yorsa, mitler de bir k\xfclt\xfcr\xfcn kolektif bilin\xe7alt\u0131n\u0131 ta\u015f\u0131r."},imge:{term:'\u0130mge / Sembol',short:'Bir kavram\u0131 g\xf6rsel/duyusal yo\u011funlukta ta\u015f\u0131yan bi\xe7im.',long:"\u0130mge ya da sembol, soyut bir ger\xe7e\u011fi somut bir bi\xe7ime b\xfcr\xfcnd\xfcren ara\xe7t\u0131r. Mandala b\xfct\xfcnl\xfc\u011f\xfc, y\u0131lan d\xf6n\xfc\u015f\xfcm\xfc, a\u011fa\xe7 ya\u015fam\u0131, su bilin\xe7alt\u0131n\u0131 ta\u015f\u0131r.\n\nBir sembol\xfcn g\xfcc\xfc, onun \xe7ok katmanl\u0131 olu\u015fundad\u0131r. Tek anlama indirgenmez \u2014 ki\u015fiye, k\xfclt\xfcre, ana g\xf6re farkl\u0131 tonlarda konu\u015fur. Sakin Mitler'de 30 evrensel imge yer al\u0131r."},"r\xfcya":{term:'R\xfcyada G\xf6rmek',short:'Bir sembol r\xfcya i\xe7inde geldi\u011finde ne s\xf6yl\xfcyor?',long:"Jung'a g\xf6re r\xfcyalar, bilin\xe7alt\u0131n\u0131n bilin\xe7le kurdu\u011fu en do\u011frudan diyalog kanal\u0131d\u0131r. Bir arketip ya da mit r\xfcyanda g\xf6r\xfcld\xfc\u011f\xfcnde, \xe7o\u011funlukla i\xe7sel bir denge ya da bir fark\u0131ndal\u0131k \xe7a\u011fr\u0131s\u0131 ta\u015f\u0131r.\n\nAyn\u0131 sembol uyan\u0131k hayatta kar\u015f\u0131na \xe7\u0131kt\u0131\u011f\u0131nda farkl\u0131 bir \u015fey s\xf6yler; r\xfcyada g\xf6r\xfcld\xfc\u011f\xfcnde ise bilin\xe7d\u0131\u015f\u0131n\u0131n i\u015flemekte oldu\u011fu i\xe7sel bir ger\xe7e\u011fi i\u015faret eder. Her kartta hem r\xfcya hem ger\xe7ek hayat yorumu birlikte sunulur."},"ger\xe7ek":{term:'Ger\xe7ek Hayatta',short:'Bir sembol uyan\u0131k deneyimde kar\u015f\u0131na \xe7\u0131kt\u0131\u011f\u0131nda ne s\xf6yl\xfcyor?',long:"Bir arketip, mit ya da sembol\xfcn uyan\u0131k hayatta belirmesi \u2014 bir kitapta g\xf6rmek, bir ki\u015fide tan\u0131mak, art arda denk gelmek, \u0131srarla tekrar etmek \u2014 onun \u015fu an seninle bir ileti\u015fim kurmaya \xe7al\u0131\u015ft\u0131\u011f\u0131n\u0131 g\xf6sterir.\n\n\"E\u015fzamanl\u0131l\u0131k\" (synchronicity) dedi\u011fimiz olay tam olarak budur. Jung bunu, d\u0131\u015f olaylar\u0131n i\xe7 s\xfcre\xe7le anlaml\u0131 bi\xe7imde \xf6rt\xfc\u015fmesi olarak tan\u0131mlar."},bul:{term:'Rehber Mitini Bulmak',short:'\u0130ki yol: sorularla ya da do\u011fum bilgileriyle.',long:"Rehber arketip ve mitini bulmak i\xe7in iki yol vard\u0131r:\n\n\u2022 Sorularla Ke\u015ffet: 7 k\u0131sa soru. Cevaplar\u0131ndaki \xf6r\xfcnt\xfc, hangi arketipin bu d\xf6nemde sana en g\xfc\xe7l\xfc e\u015flik etti\u011fini g\xf6sterir.\n\n\u2022 Do\u011fum Bilgilerimle Bul: Do\u011fum tarihi, saati ve \u015fehri. Hayat Yolu say\u0131n, do\u011fdu\u011fun mevsimin enerjisi ve do\u011fum saatinin tonu birle\u015ferek sana \xf6zel bir arketip + mit + sembol \xfc\xe7l\xfcs\xfc \xf6neriyor."},hafta:{term:'Haftal\u0131k Rehber',short:'Bir d\xf6nem boyunca seninle olan ge\xe7ici arketip.',long:"Arketipinin tamam\u0131 seninle do\u011far, \xf6m\xfcr boyu kal\u0131r. Haftal\u0131k rehber ise belirli bir d\xf6neminde sana e\u015flik eden ge\xe7ici fig\xfcrd\xfcr. Bir s\u0131nav, bir d\xf6n\xfc\u015f\xfcm, bir kriz an\u0131nda yan\u0131na gelir; g\xf6revini tamamlay\u0131nca yerini ba\u015fka birine b\u0131rak\u0131r.\n\nSakin Mitler'de her hafta evrensel bir arketip rotasyonla gelir; do\u011fum bilgilerin tamamsa ek olarak ki\u015fisel haftal\u0131k rehberin de hesaplan\u0131r."},hayatYolu:{term:'Hayat Yolu Say\u0131s\u0131',short:'Do\u011fum tarihinin numerolojik \xf6zeti \u2014 ana enerjini g\xf6sterir.',long:"Hayat Yolu say\u0131s\u0131, do\u011fum tarihinin t\xfcm rakamlar\u0131n\u0131n tek bir say\u0131ya indirgenmesiyle bulunur (\xf6rn. 15.06.1990 \u2192 1+5+0+6+1+9+9+0=31\u21924).\n\n1'den 9'a, ek olarak usta say\u0131lar\u0131 11, 22 ve 33. Her say\u0131 belirli bir arketipi temsil eder: \xd6nc\xfc, Arabulucu, Yarat\u0131c\u0131, Yap\u0131c\u0131, \xd6zg\xfcr Ruh, Sevgi El\xe7isi, Bilge, G\xfc\xe7 ve \xd6\u011fretmen."},numeroloji:{term:'Numeroloji',short:'Say\u0131lar\u0131n ard\u0131ndaki ruhsal anlamlar\u0131 okuma sanat\u0131.',long:"Numeroloji, say\u0131lar\u0131n sembolik ve ruhsal anlamlar\u0131n\u0131 inceleyen antik bir bilgi sistemidir. Do\u011fum tarihin ve isminin harfleri, ki\u015fili\u011finin farkl\u0131 katmanlar\u0131n\u0131 g\xf6steren say\u0131lara d\xf6n\xfc\u015ft\xfcr\xfcl\xfcr.\n\nD\xf6rt temel say\u0131: Hayat Yolu (kaderin), \u0130fade (yetenekler), Ruh \u0130ste\u011fi (i\xe7sel arzular) ve Ki\u015filik (d\u0131\u015fa yans\u0131tt\u0131\u011f\u0131n y\xfcz). Her biri farkl\u0131 bir aynad\u0131r."},humanDesign:{term:'Human Design',short:'Karar verme stratejini g\xf6steren modern sentez.',long:"Human Design, astroloji, I-Ching, Kabala, \xe7akralar ve kuantum fizi\u011fini birle\u015ftiren modern bir sistemdir. Do\u011fum bilgilerine g\xf6re be\u015f ana tipten birine d\xfc\u015fersin: Jenerat\xf6r, Manifesting Jenerat\xf6r, Projekt\xf6r, Manifestor ve Reflekt\xf6r.\n\nHer tipin kendi karar verme stratejisi ve \"Not-Self\" temalar\u0131 vard\u0131r. Stratejine g\xf6re ya\u015famak i\xe7sel s\xfcrt\xfcnmeyi azalt\u0131r."},persona:{term:'Persona',short:'D\xfcnyaya g\xf6sterdi\u011fin maske.',long:"Persona, Latince \"maske\" demektir. Jung'a g\xf6re, d\xfcnyaya \xe7\u0131karken giydi\u011fin sosyal y\xfczd\xfcr \u2014 i\u015fteki kimli\u011fin, ailedeki rol\xfcn, g\xf6r\xfcn\xfcrdeki ki\u015fili\u011fin.\n\nPersona zorunludur; tamamen onsuz toplumsal hayat s\xfcrd\xfcremezsin. Ama persona ile tamamen \xf6zde\u015fle\u015firsen kendi ger\xe7ek y\xfcz\xfcn\xfc kaybedersin."},"g\xf6lge":{term:'G\xf6lge',short:'Kendinde kabul etmedi\u011fin yan.',long:"G\xf6lge, bilin\xe7li olarak reddetti\u011fin, bast\u0131rd\u0131\u011f\u0131n ya da kabul edemedi\u011fin t\xfcm \xf6zelliklerin toplam\u0131d\u0131r. \xd6fke, k\u0131skan\xe7l\u0131k, h\u0131rs, tembellik \u2014 bunlar genelde g\xf6lgenin par\xe7alar\u0131d\u0131r. Ama bazen sahiplenilmemi\u015f yarat\u0131c\u0131l\u0131k, cesaret ve sevgi de g\xf6lgede saklan\u0131r.\n\nJung der ki: \"G\xf6lgeni bilmek ayd\u0131nlanmaktan de\u011fil, karanl\u0131\u011f\u0131n\u0131 bilin\xe7li g\xf6rmekten gelir.\""},anima:{term:'Anima / Animus',short:'\u0130\xe7indeki kar\u015f\u0131-cins ruh.',long:"Anima, erkek psikesindeki di\u015fil ruhtur \u2014 sezgi, duygu, ilham. Animus ise kad\u0131n psikesindeki eril ruh \u2014 mant\u0131k, irade, s\u0131n\u0131r kurma.\n\nBunlar bilin\xe7alt\u0131nda uyuyorsa d\u0131\u015far\u0131ya yans\u0131t\u0131l\u0131r \u2014 ki\u015fi kar\u015f\u0131 cinste asl\u0131nda kendi i\xe7sel imgesinin pe\u015finden ko\u015far. Tan\u0131n\u0131nca, i\xe7sel bir denge ve yarat\u0131c\u0131l\u0131k olarak entegre olur."},self:{term:'Self (\xd6z)',short:'Psikenin merkezi ve b\xfct\xfcnl\xfc\u011f\xfc.',long:"Self, Jung'un kuram\u0131nda, bilin\xe7 ve bilin\xe7alt\u0131n\u0131n birlikte olu\u015fturdu\u011fu psi\u015fik merkez ve b\xfct\xfcnl\xfckt\xfcr. Egonun \xe7ok \xf6tesinde, \"i\xe7sel Tanr\u0131-imgesi\" olarak da adland\u0131r\u0131l\u0131r.\n\nBireyle\u015fme s\xfcrecinin var\u0131\u015f noktas\u0131 Self'tir. Mandalada g\xf6r\xfclen merkez, mitlerde g\xf6r\xfclen \"b\xfcy\xfck ya\u015fl\u0131\" ya da \"kutsal \xe7ocuk\", hep Self'in sembolleridir."},trickster:{term:'Trickster (Hilebaz)',short:'Kural\u0131 k\u0131rarak ger\xe7e\u011fi g\xf6steren oyunbaz.',long:"Trickster, mitolojide kurallar\u0131 \xe7i\u011fneyen ama bu sayede bir hakikati g\xf6steren fig\xfcrd\xfcr \u2014 Hermes, Loki, Coyote, Nasreddin Hoca, Kelo\u011flan.\n\nModern hayatta Trickster, beklenmedik \u015fakalar\u0131n, yarat\u0131c\u0131 kaosun ve s\u0131n\u0131r a\u015fan ilham\u0131n kayna\u011f\u0131d\u0131r. G\xf6lge yan\u0131nda ise manip\xfclat\xf6r ve doland\u0131r\u0131c\u0131 olarak g\xf6r\xfcn\xfcr."},kahraman:{term:'Kahraman',short:'\xc7a\u011fr\u0131y\u0131 duyup e\u015fi\u011fi ge\xe7en ruh.',long:"Kahraman arketipi, i\xe7sel ya da d\u0131\u015fsal bir \xe7a\u011fr\u0131ya yan\u0131t vererek bildi\u011fi d\xfcnyadan ayr\u0131lan, s\u0131nanan, g\xf6lgesiyle y\xfczle\u015fen ve d\xf6n\xfcp \xf6d\xfcl\xfcn\xfc payla\u015fan ki\u015fidir. Joseph Campbell'\u0131n \"monomit\" haritas\u0131 bu yolculu\u011fu anlat\u0131r.\n\nModern hayatta kahraman\u0131 her b\xfcy\xfck ge\xe7i\u015fte aktif olur: yeni i\u015f, yeni \u015fehir, ebeveynlik, hastal\u0131k. Korku do\u011fal \u2014 kahraman korkmaz de\u011fil, korkuya ra\u011fmen ilerler."},"bilgeYa\u015fl\u0131":{term:'Bilge Ya\u015fl\u0131',short:'Zor anda yol g\xf6steren i\xe7 ses.',long:"Bilge Ya\u015fl\u0131 (senex), mitolojide Merlin, Gandalf, H\u0131z\u0131r, Yoda gibi fig\xfcrlerle temsil edilir. Yolculu\u011fun en s\u0131k\u0131\u015f\u0131k an\u0131nda belirip \"yol \u015furadan\" diyen i\xe7 sestir.\n\nJung'a g\xf6re bilge ya\u015fl\u0131, krizde bilin\xe7alt\u0131ndan y\xfckselen bilgeliktir. Modern kar\u015f\u0131l\u0131\u011f\u0131: do\u011fru anda s\xf6z alan terapist, mentor, d\xfcr\xfcst dost."},"i\xe7\xc7ocuk":{term:'\u0130\xe7 \xc7ocuk',short:'H\xe2l\xe2 i\xe7inde ya\u015fayan ilk halin.',long:"\u0130\xe7 \xc7ocuk arketipi iki y\xf6n ta\u015f\u0131r: ilahi \xe7ocuk (saf ne\u015fe, merak, hayret) ve yaral\u0131 \xe7ocuk (terk edilmi\u015flik, ihmal, korku).\n\nBir yeti\u015fkinin krizleri genellikle i\xe7 \xe7ocu\u011fun bak\u0131m \xe7\u0131\u011fl\u0131\u011f\u0131d\u0131r. Onu g\xf6rmek, ona sahip \xe7\u0131kmak, hem yarat\u0131c\u0131l\u0131\u011f\u0131 hem dayan\u0131kl\u0131l\u0131\u011f\u0131 \xe7a\u011f\u0131r\u0131r."},sakinAilesi:{term:'Sakin Ailesi',short:'Ayn\u0131 k\xf6kten beslenen rehber uygulamalar serisi.',long:"Sakin Ailesi, ayn\u0131 ruhu farkl\u0131 sembol dilleriyle ta\u015f\u0131yan rehber uygulamalardan olu\u015fur:\n\n\u2022 Sakin Hayvan \u2014 Anadolu'dan d\xfcnyaya 50 totem hayvan.\n\u2022 Sakin Mitler \u2014 Jung'un izinde arketipler, mitler ve sembolik imgeler.\n\nTasar\u0131m ayn\u0131, i\xe7erik farkl\u0131. Her biri ruhun ba\u015fka bir k\xf6\u015fesine konu\u015fur."}}},781,[]);
